<span class="line"><span style="color:#F92672;">        if</span><span style="color:#F8F8F2;"> i </span><span style="color:#F92672;">&lt;</span><span style="color:#F8F8F2;"> min_value:  </span><span style="color:#88846F;"># 使用 min_value 而不是 lst[0]</span></span>
